const todoInput = document.getElementById('todo-input');
const addBtn = document.getElementById('add-btn');
const todoList = document.getElementById('todo-list');

function addTodo() {
  const taskText = todoInput.value.trim();
  if (!taskText) return;

  const li = document.createElement('li');
  li.className = 'flex items-center justify-between p-2.5 bg-slate-900 border border-slate-700 rounded-lg group transition-all';

  const textSpan = document.createElement('span');
  textSpan.className = 'text-slate-200 text-sm cursor-pointer select-none flex-1';
  textSpan.textContent = taskText;
  textSpan.addEventListener('click', () => {
    textSpan.classList.toggle('line-through');
    textSpan.classList.toggle('opacity-50');
  });

  const deleteBtn = document.createElement('button');
  deleteBtn.className = 'text-xs text-rose-500 hover:text-rose-400 font-semibold px-2 py-1 rounded transition-colors';
  deleteBtn.textContent = 'Delete';
  deleteBtn.addEventListener('click', () => {
    li.remove();
  });

  li.appendChild(textSpan);
  li.appendChild(deleteBtn);
  todoList.appendChild(li);

  todoInput.value = '';
}

addBtn.addEventListener('click', addTodo);
todoInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') addTodo();
});
